import{_ as t,o as e,c as o,a2 as r}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6903_巨漢/20260502/F01_營收因子與定價權分析_財務分析專家.md","filePath":"審計報告庫/財務審計/6903_巨漢/20260502/F01_營收因子與定價權分析_財務分析專家.md"}'),n={name:"審計報告庫/財務審計/6903_巨漢/20260502/F01_營收因子與定價權分析_財務分析專家.md"};function i(l,a,s,_,h,d){return e(),o("div",null,[...a[0]||(a[0]=[r('<h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營收成長或衰退的實質因子分析：是由於「銷量增加 (Volume Up)」還是「單價調整 (Price Up)」？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>巨漢 2025 年營收 31.77 億（YoY +72.8%），主因半導體廠務工程進入完工認列高峰期，屬「<strong>銷量驅動型成長</strong>」。H2 營收 21.11 億佔全年 66%，顯示工程認列高度集中在下半年。毛利率連年下滑（40.6%→27.7%），定價權趨弱。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p>A-（良偏中上）。營收爆發力強，2025 年全年 YoY +72.8%，但結構上存在兩大隱憂：(1) 毛利率 3 年內從 40.6% 下滑至 27.7%（-12.9pp），定價權顯著衰退，反映產業競爭加劇；(2) H2 營收佔比 66%，集中於下半年入帳，營收波動大。</p><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><ol><li><p><strong>營收結構</strong>：巨漢主營半導體廠房機電/無塵室統包工程（佔營收 ~90%），屬工程統包（EPC）模式。營收認列採「完工比例法」，因此單期營收波動大。2024 年營收 18.38 億（僅 8 個月數據），2025 年 31.77 億（完整全年），可比性有限。2026Q1 營收 8.56 億（YoY +58%），動能持續。</p></li><li><p><strong>P/V 拆解</strong>：由於工程案無明確的「單價 × 數量」，以「平均每月認列營收」替代：2024 年月均 2.3 億（8 個月），2025 年月均 2.65 億（12 個月），月均增長約 15%。營收成長主驅動力為<strong>承接案件數量大增</strong>（Volume Up），而非單價調升。</p></li><li><p><strong>獲利品質</strong>：營益率從 35.8% 降至 23.7%（-12.1pp），降幅接近毛利率，顯示 OPM 下滑並非費用失控（費用率僅從 4.8% 升至 4.0%），而是<strong>毛利結構惡化</strong>——低毛利工程案佔比提高，稀釋整體獲利。</p></li></ol><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><ol><li><strong>毛利率持續惡化風險</strong>：3 年毛利率從 40.6% 跌至 27.7%，若 2026 年再跌至 25% 以下，即便營收維持高成長，營業利益也將縮水。關鍵在於公司能否承接高毛利先進製程廠房案，而非一般廠務案。</li><li><strong>工程案認列不確定性</strong>：營收高度集中下半年，存在工程延宕或變更導致的認列遞延風險。2025 年 Q3 前營收僅 10.66 億（34%），最後一季單季就認列 13.29 億（42%），流動性管理壓力大。</li><li><strong>同業競爭壓力</strong>：聖暉、帆宣等同業毛利率約 20-25%，巨漢過去享有超額利潤（40%+），但目前正快速向產業均值回歸。當毛利率降至 25% 以下時，將失去差異化優勢。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>FinMind：TaiwanStockMonthRevenue（2024-2025）</li><li>FinMind：TaiwanStockFinancialStatements（2023-2025）</li><li>財務分析工具.py：revenue_bridge 6903、margin_analysis 6903</li></ul>',12)])])}const u=t(n,[["render",i]]);export{c as __pageData,u as default};
